''
import React from 'react'

const HomeBanner = () => {
  const [jobTitle, setJobTitle] = useState('');
  const [location, setLocation] = useState('');
  const [category, setCategory] = useState('');
  return (
    <div>
      <h2>Find Your Dream Job Today!</h2>
      <p>connecting talent with opportunity: Your Gateaway tp Career Success.</p>
{/* <div className='flex items-center w-full bg-white rounded-full max-w-4xl mx-auto overflow-hidden'>
  <input className='flex-1 px-3 py-4 text-gray-800 focus:outline-none' type="text"
  placeholder='Job title' />
   <div className="w-px h-8 bg-gray-800" ></div>

  <select  className="px-4 py-3 text-gray-700 bg-transparent focus:outline-none"
   name="" id=""></select>
  <select name="" id=""
  className="px-4 py-3 text-gray-700 bg-transparent focus:outline-none"></select>
  <button>ok</button>
</div> */}

<div className="flex items-center bg-white rounded-full shadow-md overflow-hidden w-full max-w-4xl mx-auto">
      {/* Job Title Input */}
      <input
        type="text"
        placeholder="Job Title or Company"
        value={jobTitle}
        onChange={(e) => setJobTitle(e.target.value)}
        className="flex-1 px-4 py-3 text-gray-700 focus:outline-none"
      />

      {/* Divider */}
      <div className="w-px h-8 bg-gray-300" />

      {/* Location Select */}
      <select
        value={location}
        onChange={(e) => setLocation(e.target.value)}
        className="px-4 py-3 text-gray-700 bg-transparent focus:outline-none"
      >
        <option value="">Select Location</option>
        <option value="ny">New York</option>
        <option value="sf">San Francisco</option>
      </select>

      {/* Divider */}
      <div className="w-px h-8 bg-gray-300" />

      {/* Category Select */}
      <select
        value={category}
        onChange={(e) => setCategory(e.target.value)}
        className="px-4 py-3 text-gray-700 bg-transparent focus:outline-none"
      >
        <option value="">Select Category</option>
        <option value="dev">Developer</option>
        <option value="design">Designer</option>
      </select>

      {/* Search Button */}
      <button className="bg-teal-600 hover:bg-teal-700 text-white px-6 py-3 rounded-full flex items-center gap-2">
        <svg
          xmlns="http://www.w3.org/2000/svg"
          fill="none"
          viewBox="0 0 24 24"
          strokeWidth={2}
          stroke="currentColor"
          className="w-5 h-5"
        >
          <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-4.35-4.35m0 0A7.5 7.5 0 1110.5 3a7.5 7.5 0 016.15 13.65z" />
        </svg>
        Search Job
      </button>
    </div>

    </div>
  )
}

export default HomeBanner
